/* Fade + drop animation */
@keyframes fadeDrop {
  0% {
    opacity: 0;
    transform: translateY(-40px);
  }
  100% {
    opacity: 1;
    transform: translateY(0);
  }
}

/* Apply ONLY to selected rows */
.row-row-ufc8-bg > div,
.row-row-oyxi-bg > div {
  opacity: 0;
  transform: translateY(-40px);
  animation: fadeDrop 0.6s ease-out forwards;
}



/* glitch with color cycling */
@keyframes glitchHoverColor {
  0%   { transform: translate(0);    filter: none; }

  15%  { transform: translate(-2px,1px); filter: hue-rotate(0deg) contrast(1.6) blur(0.5px); }     /* red-ish */
  30%  { transform: translate(2px,-1px); filter: hue-rotate(120deg) contrast(1.5); }               /* green */
  45%  { transform: translate(-1px,1px); filter: hue-rotate(60deg) brightness(1.4); }              /* yellow */
  60%  { transform: translate(1px,-1px); filter: hue-rotate(270deg) contrast(1.6); }               /* purple */
  75%  { transform: translate(-1px,0);   filter: hue-rotate(180deg) blur(0.8px); }                 /* cyan-ish chaos */

  100% { transform: translate(0);    filter: none; }
}

/* lock layout */
[class*="choice-???"] {
  overflow: hidden;
  display: inline-block;
  transform-origin: center;
}

/* apply glitch */
[class*="choice-???"]:hover,
[class*="choice-???"]:hover * {
  animation: glitchHoverColor 0.2s steps(2, end) infinite;
  will-change: transform, filter;
}


/* Base state */
[class*="mul"],
[class*="god"] {
  filter: brightness(1);
  transition: filter 2s ease !important;
}

/* Hover glow */
[class*="mul"]:hover,
[class*="god"]:hover {
  filter: brightness(1.2) !important;
  transition: filter 3s ease !important;
}

/* images inside mul + god */
[class*="mul"] img,
[class*="god"] img {
  transition: transform 2s ease;
}

/* gentler hover zoom */
[class*="mul"]:hover img,
[class*="god"]:hover img {
  transform: scale(1.04);   /* was ~1.08 */
  transition: transform 3s ease;
}



/* FAST two-phase glitch */
@keyframes spiderGlitchSettleFast {

  /* CHAOS (0 → ~45%) */
  0% {
    opacity: 0;
    transform: translate(0);
    filter: blur(6px) contrast(2);
  }

  10% {
    opacity: 0.3;
    transform: translate(-12px, 5px);
    filter: hue-rotate(0deg) blur(4px) contrast(2);
  }

  20% {
    transform: translate(12px, -5px);
    filter: hue-rotate(120deg);
  }

  30% {
    transform: translate(-10px, 4px);
    filter: hue-rotate(60deg) contrast(2);
  }

  40% {
    opacity: 0.6;
    transform: translate(10px, -4px);
    filter: hue-rotate(270deg) blur(2px);
  }

  /* SETTLE (45 → 100%) */
  60% {
    opacity: 0.8;
    transform: translate(-5px, 2px);
    filter: blur(1px);
  }

  75% {
    opacity: 0.9;
    transform: translate(3px, -1px);
    filter: none;
  }

  100% {
    opacity: 1;
    transform: translate(0);
    filter: none;
  }
}

/* APPLY */
[class*="choice-qmia"],
[class*="choice-l5tj"],
[class*="choice-zlwt_dup"],
[class*="choice-lweg"] {
  opacity: 0;
  animation: spiderGlitchSettleFast 1.4s steps(2, end) forwards !important;
}
